import React from 'react';
import {
  MapPin,
  CreditCard,
  ShoppingBag
} from 'lucide-react';

function CheckoutPage({
  user,
  cart,
  profileData,
  loading,
  error,
  setError,
  setLoading,
  setCart,
  setCurrentPage,
  ordersAPI,
  cartAPI,
  getUserIdFromToken,
  loadOrders,
  openRazorpay
}) {

  const totalAmount = cart.reduce(
    (sum, item) => sum + item.price * item.quantity,
    0
  );

  return (
    <div className="min-h-screen bg-gradient-to-b from-slate-50 via-white to-slate-50">
      {/* HEADER */}
      <header className="bg-white shadow-md sticky top-0 z-40 border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center gap-4">
          <button
            onClick={() => setCurrentPage('cart')}
            className="text-gray-700 hover:text-blue-600 p-2 rounded-lg"
          >
            ŌåÉ
          </button>
          <h1 className="text-2xl font-bold text-blue-600">Secure Checkout</h1>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-6 py-8">
        {error && (
          <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded mb-6">
            {error}
          </div>
        )}

        <div className="grid lg:grid-cols-3 gap-8">
          {/* LEFT */}
          <div className="lg:col-span-2 space-y-6">

            {/* ADDRESS */}
            <div className="bg-white p-6 rounded-xl shadow">
              <h2 className="text-xl font-bold flex items-center gap-2 mb-4">
                <MapPin className="text-blue-600" /> Shipping Address
              </h2>

              {profileData.addresses?.map(addr => (
                <label key={addr._id} className="block border p-4 rounded mb-2">
                  <input
                    type="radio"
                    name="address"
                    value={addr._id}
                    defaultChecked={addr.IsDefault}
                    className="mr-2"
                  />
                  {addr.AddressLine1}, {addr.City}
                </label>
              ))}
            </div>

            {/* PAYMENT */}
            <div className="bg-white p-6 rounded-xl shadow">
              <h2 className="text-xl font-bold flex items-center gap-2 mb-4">
                <CreditCard className="text-blue-600" /> Payment Method
              </h2>

              <label className="block border p-4 rounded mb-2">
                <input type="radio" name="paymentMethod" value="COD" defaultChecked /> COD
              </label>

              <label className="block border p-4 rounded">
                <input type="radio" name="paymentMethod" value="Online" /> Online (Razorpay)
              </label>
            </div>

            {/* ITEMS */}
            <div className="bg-white p-6 rounded-xl shadow">
              <h2 className="text-xl font-bold flex items-center gap-2 mb-4">
                <ShoppingBag className="text-blue-600" /> Items ({cart.length})
              </h2>

              {cart.map(item => (
                <div key={item.productId} className="flex justify-between mb-2">
                  <span>{item.productName}</span>
                  <span>Ōé╣{item.price * item.quantity}</span>
                </div>
              ))}
            </div>
          </div>

          {/* RIGHT */}
          <div className="bg-white p-6 rounded-xl shadow h-fit">
            <h3 className="text-xl font-bold mb-4">Order Summary</h3>

            <p className="flex justify-between mb-2">
              <span>Total</span>
              <span className="font-bold">Ōé╣{totalAmount}</span>
            </p>

            <button
              disabled={loading}
              onClick={async () => {
                try {
                  setError('');
                  setLoading(true);

                  const addressId =
                    document.querySelector('input[name="address"]:checked')?.value;
                  const paymentMethod =
                    document.querySelector('input[name="paymentMethod"]:checked')?.value;

                  if (!addressId) throw new Error('Select address');

                  const orderRes = await ordersAPI.confirm(addressId);
                  const orderId = orderRes.data.orderId || orderRes.data.id;

                  if (paymentMethod === 'Online') {
                    await openRazorpay({ orderId, amount: totalAmount, user });
                    return;
                  }

                  await cartAPI.clear(getUserIdFromToken());
                  setCart([]);
                  await loadOrders();
                  setCurrentPage('profile');

                  alert('Order placed!');
                } catch (e) {
                  setError(e.message);
                } finally {
                  setLoading(false);
                }
              }}
              className="w-full bg-blue-600 text-white py-3 rounded"
            >
              {loading ? 'Processing...' : 'Place Order'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default CheckoutPage;
